before_code:
library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

entity barrel_shifter is
    port (
        data : in std_logic_vector(31 downto 0);
        shift_amount : in integer range 0 to 31;
        shift_direction : in std_logic;
        result : out std_logic_vector(31 downto 0)
    );
end barrel_shifter;

architecture rtl of barrel_shifter is
begin
    process(data)
    begin
        if (shift_direction = '0') then
            result <= std_logic_vector(shift_left(unsigned(data), shift_amount));
        else
            result <= std_logic_vector(shift_right(unsigned(data), shift_amount));
        end if;
    end process;
end rtl;

after_code:
library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

entity barrel_shifter is
    port (
        data : in std_logic_vector(31 downto 0);
        shift_amount : in integer range 0 to 31;
        shift_direction : in std_logic;
        result : out std_logic_vector(31 downto 0)
    );
end barrel_shifter;

architecture rtl of barrel_shifter is
begin
    process(data, shift_amount, shift_direction)
    begin
        if (shift_direction = '0') then
            result <= std_logic_vector(shift_left(unsigned(data), shift_amount));
        else
            result <= std_logic_vector(shift_right(unsigned(data), shift_amount));
        end if;
    end process;
end rtl;
